// Lists every top-level folder under the project root, compares against
// the processed-projects ledger, and returns only folders not yet seen.
// This node never touches file contents -- names and existence only.

const fs = require('fs');
const path = require('path');

const PROJECT_ROOT = $env.CIRCLEOFCARE_PROJECT_ROOT || 'Working';
const LEDGER_PATH = path.join('Shared', 'processed_projects.json');

let ledger = [];
try {
  const raw = fs.readFileSync(LEDGER_PATH, 'utf8');
  ledger = JSON.parse(raw);
} catch (e) {
  // No ledger yet on a fresh install -- treat as empty, not an error.
  ledger = [];
}

const ledgerSet = new Set(ledger);

let entries = [];
try {
  entries = fs.readdirSync(PROJECT_ROOT, { withFileTypes: true });
} catch (e) {
  // Project root missing or unreadable -- surface as zero results,
  // not a thrown exception that would kill the whole poll cycle.
  return [];
}

const newProjects = entries
  .filter(e => e.isDirectory())
  .map(e => e.name)
  .filter(name => !ledgerSet.has(name))
  // Reject anything that isn't a plain alphanumeric/underscore/hyphen
  // folder name before it ever becomes a project identifier downstream --
  // same discipline as the schema field-name allowlist (A3).
  .filter(name => /^[A-Za-z0-9_-]{1,64}$/.test(name));

return newProjects.map(name => ({ json: { project_prefix: name } }));

// Records this project as claimed by a Decode run the moment the
// handoff fires -- before Decode itself does anything -- so a project
// can never be picked up twice by overlapping poll cycles. This node
// never re-derives the ledger from a live scan; it only appends.

const fs = require('fs');
const path = require('path');

const LEDGER_PATH = path.join('Shared', 'processed_projects.json');

let ledger = [];
try {
  ledger = JSON.parse(fs.readFileSync(LEDGER_PATH, 'utf8'));
} catch (e) {
  ledger = [];
}

if (!ledger.includes($input.item.json.project_prefix)) {
  ledger.push($input.item.json.project_prefix);
}

fs.writeFileSync(LEDGER_PATH, JSON.stringify(ledger, null, 2), 'utf8');

return $input.item;
